import { APP_INITIALIZER } from '@angular/core';
import { provideRouter } from '@angular/router';
import { provideAnimations } from '@angular/platform-browser/animations';
import { provideHttpClient } from '@angular/common/http';
import { provideStore } from '@ngrx/store';
import { provideStoreDevtools } from '@ngrx/store-devtools';
import { provideEffects } from '@ngrx/effects';
import { provideRouterStore, RouterState } from '@ngrx/router-store';
import { provideEntityData, EntityDefinitionService, EntityDataService } from '@ngrx/data';
import { environment } from '../environments/environment';
import { routes } from './app.routes';
import { reducers, metaReducers } from './reducers';
import { AuthEffects } from './auth/auth.effects';
import { NotesDataService } from './notes/services/notes-data.service';
import { compareNotes } from './notes/model/note';
// Entity metadata
const entityMetadata = {
  Note: {
    sortComparer: compareNotes,
    entityDispatcherOptions: {
      optimisticUpdate: true
    }
  }
};
export const appConfig = {
  providers: [provideRouter(routes), provideAnimations(), provideHttpClient(), provideStore(reducers, {
    metaReducers,
    runtimeChecks: {
      strictStateImmutability: true,
      strictActionImmutability: true,
      strictActionSerializability: true,
      strictStateSerializability: true
    }
  }), provideStoreDevtools({
    maxAge: 25,
    logOnly: environment.production
  }), provideEffects([AuthEffects]), provideRouterStore({
    stateKey: 'router',
    routerState: RouterState.Minimal
  }), provideEntityData({
    entityMetadata
  }),
  // Initialize entity services
  {
    provide: APP_INITIALIZER,
    useFactory: (eds, entityDataService, notesDataService) => {
      return () => {
        eds.registerMetadataMap(entityMetadata);
        entityDataService.registerService('Note', notesDataService);
      };
    },
    deps: [EntityDefinitionService, EntityDataService, NotesDataService],
    multi: true
  }]
};
